void Flat::implicit_uses(RegisterSet &uses) const {
  if (inst_.saddr == 0x7F)
    return;
  if (inst_.seg == 1) {
    uses.expand(RegisterRef{RegClass::SGPR, static_cast<uint16_t>(inst_.saddr), 1});
  } else if (inst_.seg == 2) {
    uses.expand(RegisterRef{RegClass::SGPR, static_cast<uint16_t>(inst_.saddr), 2});
  }
}

